def min_path_sum(grid):
    if not grid or not grid[0]:
        return 0
    m, n = len(grid), len(grid[0])
    g = [row[:] for row in grid]
    for i in range(m):
        for j in range(n):
            if i == 0 and j == 0:
                continue
            elif i == 0:
                g[i][j] += g[i][j-1]
            elif j == 0:
                g[i][j] += g[i-1][j]
            else:
                g[i][j] += min(g[i-1][j], g[i][j-1])
    return g[m-1][n-1]

